using System;

interface IVehicle
{
    void Start();
    void Stop();
}

class Car : IVehicle
{
    public void Start()
    {
        Console.WriteLine("Avtomobil işə salındı.");
    }

    public void Stop()
    {
        Console.WriteLine("Avtomobil dayandırıldı.");
    }
}

class Bicycle : IVehicle
{
    public void Start()
    {
        Console.WriteLine("Velosiped hərəkətə başladı.");
    }

    public void Stop()
    {
        Console.WriteLine("Velosiped dayandırıldı.");
    }
}

class Program
{
    static void Main(string[] args)
    {
        IVehicle car = new Car();
        IVehicle bicycle = new Bicycle();

        car.Start();
        car.Stop();
        bicycle.Start();
        bicycle.Stop();
    }
}
// Output:
// Avtomobil işə salındı.
// Avtomobil dayandırıldı.
// Velosiped hərəkətə başladı.
// Velosiped dayandırıldı.

